sql:
SELECT pet_id, name 
FROM pets 
WHERE adoption_status = 'Available' AND submitter_id != 0;

SELECT DISTINCT staff.name, staff.role
FROM staff
JOIN vaccinations ON staff.staff_id = vaccinations.administered_by;

external_knowledge:
- 'recently treated' refers to pets that have had a treatment in the last 30 days;
- 'medical staff' specifically means those staff members belonging to the Medical department;
- 'within the last month' means the treatment date is within the last 30 days from the current date;

sql:
SELECT p.name AS "Pet Name", v.vaccine_name AS "Vaccine Name"
FROM pets p
INNER JOIN vaccinations v ON p.pet_id = v.pet_id;

SELECT T1.name AS PetName, T2.adopter_name AS AdopterName
FROM pets AS T1
INNER JOIN adoptions AS T2 ON T1.pet_id = T2.pet_id;

SELECT pet_id, name
FROM pets
WHERE adoption_status = 'adopted' OR adoption_status = 'available';
